window.PLANTUML_STDLIB.classy["types/map"]="!if %true() != $CLASSY_TYPES_MAP_PUML;!$CLASSY_TYPES_MAP_PUML = %true();;!include <classy/types/key-value-pair>;;$class(Map);  $classVar(pairs, array);;  !function Map__get_safe($this, $target);    !$pairs = $getInstanceVar($this, 'pairs');;    !if '' == $pairs;      !return '';    !endif;;    !local $current = $call($pairs, 'each');;    !while %false() != $current;      !if $target == $call($current, 'getKey');        $call($pairs, 'reset');        !return $call($current, 'getValue');      !endif;;      !$current = $call($pairs, 'each');    !endwhile;;    !return '';  !endfunction;;  $classMethod(add);    !function Map__add($this, $args);      !$key = $call($args, 'each');      !$val = $call($args, 'each');;      !$pairs = $getInstanceVar($this, 'pairs');;      !if '' == $pairs;        !$pairs = $new('array');        $setInstanceVar($this, 'pairs', $pairs);      !endif;;      !if 0 < $call($pairs, 'size');        !$result = Map__get_safe($this, $key);;        !if '' != $result;          $fail('Attempting to add key that already exists: ' + $key);        !endif;      !endif;;      !$pair = $new('KeyValuePair');      $call($pair, 'setKey', $key);      $call($pair, 'setValue', array($new('array'), $val));;      $call($pairs, 'push', $pair);      !return $this;    !endfunction;  $endclassMethod(add);;  $classMethod(get);    !function Map__get($this, $args);      !$target = $call($args, 'pop');      !$result = Map__get_safe($this, $target);;      !if '' == $result;        $fail('Map does not contain key: ' + $target);      !endif;;      !return $result;    !endfunction;  $endclassMethod(get);;  $classMethod(has);    !function Map__has($this, $args);      !$result = Map__get_safe($this, $call($args, 'pop'));;      !if '' == $result;        !$result = %false();      !else;        !$result = %true();      !endif;;      !return $result;    !endfunction;  $endclassMethod(has);$endclass(Map);;!endif".split(";");
